fn update_events_borders<C: Callbacks>(events: &[InputEvent], state: &mut C) {
    for ev in events {
        if let InputEvent::Press { x, y } = ev {
            let new_focus =
                if *x < 400 && *y < 60 { Some(0) }
                else if *x >= 400 && *x < 800 && *y < 60 { Some(1) }
                else { None };
            *FOCUSED.lock().unwrap() = new_focus;
            if *x < 400 && *y < 60 {
                state.nav(&["Margin"]);
            }
            if *x >= 400 && *x < 800 && *y < 60 {
                state.nav(&["Clickable"]);
            }
        }
    }
}

fn update_events_clickable<C: Callbacks>(events: &[InputEvent], state: &mut C) {
    for ev in events {
        if let InputEvent::Press { x, y } = ev {
            let new_focus =
                if *x < 400 && *y < 60 { Some(0) }
                else if *x >= 400 && *x < 800 && *y < 60 { Some(1) }
                else if *x < 800 && *y >= 165 && *y < 270 { Some(2) }
                else if *x < 800 && *y >= 270 && *y < 375 { Some(3) }
                else if *x < 800 && *y >= 375 && *y < 480 { Some(4) }
                else { None };
            *FOCUSED.lock().unwrap() = new_focus;
            if *x < 400 && *y < 60 {
                state.nav(&["Borders"]);
            }
            if *x >= 400 && *x < 800 && *y < 60 {
                state.nav(&["Focusable"]);
            }
            if *x < 800 && *y >= 165 && *y < 270 {
                state.click();
            }
            if *x < 800 && *y >= 270 && *y < 375 {
                state.action(&["hello"]);
            }
            if *x < 800 && *y >= 375 && *y < 480 {
                state.action(&["a", "b"]);
            }
        }
    }
}

